sys_script.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// 2.8.1    | 2022-10-24 - raj -  STRY0131148 - Add New Table for Tasker User in preparation for Out of Office - this script really only changes the Org User to match the Org Member
//
// Script Continued Below
/*jshint esnext: true */
(function executeRule(current, previous /*null when async*/) {
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
	var grRole;
	var UserPermissions = new UserInfoScripts();

	var userName = current.u_tasker_user.first_name + ' ' + current.u_tasker_user.middle_name + ' ' + current.u_tasker_user.last_name;

	if(current.getDisplayValue("u_default_ou")==''){
		UserPermissions.setNewDefaultOU(current.u_tasker_user);
	}

    //-----------------------------------------------------------------------------------------------------
    // Role: Task Administrator | x_153465_discovert.tasker_global_Tasking_Authority_member_admin
    //-----------------------------------------------------------------------------------------------------
    // STRY0131148 - changed tables and some field names, removed sync fields b/c not necessary
    if (current.is_task_administrator || current.is_task_administrator.changesTo('true')) {
		// Add Role
        UserPermissions.addRole(current.u_tasker_user, userName, 'x_153465_discovert.tasker_global_Tasking_Authority_member_admin');
    } else if (current.is_task_administrator.changesTo('false')) {
		// Remove Role
        UserPermissions.removeRole(current.u_tasker_user, userName, 'is_task_administrator', 'x_153465_discovert.tasker_global_Tasking_Authority_member_admin', 'GlobalRole');
    }
	// STRY0112585 - Task Executive- Update for New Member Form
    if (current.is_task_executive || current.is_task_executive.changesTo('true')) {
        UserPermissions.addRole(current.u_tasker_user, userName, 'x_153465_discovert.Task_Executive');
    } else if (current.is_task_executive.changesTo('false')) {
		// Remove Role
        UserPermissions.removeRole(current.u_tasker_user, userName, 'is_task_executive', 'x_153465_discovert.Task_Executive', 'GlobalRole');
    }	

	//-----------------------------------------------------------------------------------------------------
    // Role: Global Hierarchy Administrator | x_153465_discovert.tasker_organizational_admin
    //-----------------------------------------------------------------------------------------------------
    if (current.is_global_hierarchy_administrator || current.is_global_hierarchy_administrator.changesTo('true')) {
		// Add Role
		UserPermissions.addRole(current.u_tasker_user, userName, 'x_153465_discovert.tasker_organizational_admin');
    } else if (current.is_global_hierarchy_administrator.changesTo('false')) {
		// Remove Role
		UserPermissions.removeRole(current.u_tasker_user, userName, 'is_global_hierarchy_administrator','x_153465_discovert.tasker_organizational_admin', 'GlobalRole');
    }

    //-----------------------------------------------------------------------------------------------------
    // Role: Tasker Application Admin | x_153465_discovert.tasker_application_admin
    //-----------------------------------------------------------------------------------------------------
    if (current.is_tasker_application_administrator	 || current.is_tasker_application_administrator.changesTo('true')) {
		// Add Role
        UserPermissions.addRole(current.u_tasker_user, userName, 'x_153465_discovert.tasker_application_admin');
    } else if (current.is_tasker_application_administrator.changesTo('false')) {
		// Remove Role
        UserPermissions.removeRole(current.u_tasker_user, userName, 'is_tasker_application_administrator','x_153465_discovert.tasker_application_admin', 'GlobalRole');
    }

    //-----------------------------------------------------------------------------------------------------
    // Role: Template Permissions Administrator | x_153465_discovert.tasker_process_template_admin
    //-----------------------------------------------------------------------------------------------------
    if (current.can_manage_template_permissions	 || current.can_manage_template_permissions.changesTo('true')) {
		// Add Role
		UserPermissions.addRole(current.u_tasker_user, userName, 'x_153465_discovert.tasker_process_template_admin');
    } else if (current.can_manage_template_permissions.changesTo('false')) {
		// Remove Role
        UserPermissions.removeRole(current.u_tasker_user, userName, 'can_manage_template_permissions', 'x_153465_discovert.tasker_process_template_admin', 'GlobalRole');
	}

	//-----------------------------------------------------------------------------------------------------
    // Role: Global Template Designer | x_153465_discovert.tasker_process_template_global
    //-----------------------------------------------------------------------------------------------------
    if (current.can_manage_global_template || current.can_manage_global_template.changesTo('true')) {
		// Add Role
        UserPermissions.addRole(current.u_tasker_user, userName, 'x_153465_discovert.tasker_process_template_global');
    } else if (current.can_manage_global_template.changesTo('false')) {
		//Remove Role
        UserPermissions.removeRole(current.u_tasker_user, userName, 'can_manage_global_template', 'x_153465_discovert.tasker_process_template_global', 'GlobalRole');
    }

   //-----------------------------------------------------------------------------------------------------
    // Role: Personal Process Template Administrator | role x_153465_discovert.tasker_process_template_user
    //-----------------------------------------------------------------------------------------------------
    if (current.has_personal_template_rights || current.has_personal_template_rights.changesTo('true')) {
		// Add Role
        UserPermissions.addRole(current.u_tasker_user, userName, 'x_153465_discovert.tasker_process_template_user');
    } else if (current.has_personal_template_rights.changesTo('false')) {
		// Remove Role
        UserPermissions.removeRole(current.u_tasker_user, userName, 'has_personal_template_rights', 'x_153465_discovert.tasker_process_template_user', 'GlobalRole');
    }
})(current, previous);
